func NewStripeService(appSvc app.Service, deps Deps) (Service, error) {
    s := &service{deps: deps}
    err := appSvc.RegisterMarketplaceListing(app.RegistryItem{
        Listing: stripeListing,
        Factory: s, // builds an App instance for an install
    })
    if err != nil {
        return nil, err
    }
    return s, nil
}

